Quick Start — 3 Lines

const res = await fetch(
'https://www.currencyexchangetool.com/api/v1/convert?amount=100&from=USD&to=EUR'
);
const data = await res.json();
console.log(`100 USD = ${data.result} EUR at rate ${data.rate}`);

